site-footer.description:
Site Footer component
    Multi-section footer for full-page scroll sites.

    Layout variants:
      columns  — brand left + N link columns (default, fat footer)
      centered — stacked, center-aligned (simple sites)
      simple   — single row: brand left, links right

    Named slots: brand, default (columns), rule (decorative divider), colophon.

    Usage:
        from "chirpui/site_footer.html" import site_footer, footer_column, footer_link

        call site_footer(layout="columns")
            {% slot brand %}
                <a href="/">Logo</a>
                <p>Tagline text.</p>
            {% end %}
            {% call footer_column(title="Product") %}
                {{ footer_link("/docs", "Docs") }}
                {{ footer_link("/pricing", "Pricing") }}
            {% end %}
            {% call footer_column(title="Company") %}
                {{ footer_link("/about", "About") }}
                {{ footer_link("https://github.com/...", "GitHub", external=true) }}
            {% end %}
            {% slot rule %}<span>•</span>{% end %}
            {% slot colophon %}© 2026 My Company{% end %}
        end

site-header.description:
Site Header component
    Sticky top navigation bar for full-page scroll sites.

    Layout variants control how brand, nav, and tools are arranged:
      start        — [brand] [nav...] [spacer] [tools]  (default)
      center-brand — [nav left] [brand] [nav right | tools]
      center-nav   — [brand] [nav centered] [tools]
      split        — [brand + nav] [spacer] [tools]

    Surface variants control background treatment:
      glass       — backdrop blur, semi-transparent (default)
      solid       — opaque background
      transparent — no background (hero overlap patterns)

    Named slots: brand, nav, nav_end (center-brand right-side), tools.

    Usage:
        from "chirpui/site_header.html" import site_header, site_nav_link

        call site_header(brand_url="/", layout="start", variant="glass")
            {% slot brand %}<img src="/logo.svg" alt="Logo">{% end %}
            {% slot nav %}
                {{ site_nav_link("/docs", "Docs", glyph="#", match="prefix") }}
                {{ site_nav_link("/about", "About", match="exact") }}
            {% end %}
            {% slot tools %}theme_toggle(){% end %}
        end

        call site_header(layout="center-brand", variant="solid")
            {% slot nav %}left links{% end %}
            {% slot brand %}LOGO{% end %}
            {% slot nav_end %}right links{% end %}
            {% slot tools %}CTA button{% end %}
        end

site-nav-link.description:
Site Header component
    Sticky top navigation bar for full-page scroll sites.

    Layout variants control how brand, nav, and tools are arranged:
      start        — [brand] [nav...] [spacer] [tools]  (default)
      center-brand — [nav left] [brand] [nav right | tools]
      center-nav   — [brand] [nav centered] [tools]
      split        — [brand + nav] [spacer] [tools]

    Surface variants control background treatment:
